mapper.select:
SELECT f.*, u.nick_name as creator_name, (SELECT COUNT(*) FROM activity WHERE family_id = f.id AND del_flag = '0') as activity_count, (SELECT COUNT(*) FROM game_record WHERE family_id = f.id) as game_count FROM family f LEFT JOIN app_user u ON f.creator_id = u.id WHERE f.del_flag = '0'
AND f.name LIKE CONCAT('%', #{name}, '%')
AND f.code = #{code}
AND f.status = #{status}
ORDER BY f.create_time DESC

mapper.insert:
INSERT INTO family (
    name, avatar, code, creator_id, member_count, status,
    create_by, create_time, remark
) VALUES (
    #{name}, #{avatar}, #{code}, #{creatorId}, #{memberCount}, #{status},
    #{createBy}, NOW(), #{remark}
)

mapper.update:
UPDATE family SET name = #{name}, avatar = #{avatar}, status = #{status}, member_count = #{memberCount}, update_time = NOW()
, remark = #{remark}
WHERE id = #{id}
